#include<bits/stdc++.h>
using namespace std;
const int MAXN=1e4+5,MAXM=1e2+5;
int n,m,w[MAXN],s[MAXM],mi,ans=0;
int main(void){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;++i)scanf("%d",w+i);
    for(int i=1;i<=n;++i){mi=1;
        for(int j=2;j<=m;++j)mi=((s[mi]>s[j])?(j):(mi));s[mi]+=w[i];
    }for(int i=1;i<=m;i++)ans=max(ans,s[i]);
    printf("%d",ans);
    return false;
}
